import React, { useState, useEffect, useMemo } from 'react';
import { useSearchParams } from 'react-router-dom';
import { Chart as ChartJS, ArcElement, Tooltip, Legend } from 'chart.js';
import { Doughnut } from 'react-chartjs-2';
import './index.css';

ChartJS.register(ArcElement, Tooltip, Legend);

interface Shipment {
  id: string;
  orderNumber: string;
  status: ImportStatus;
  destination: string;
  origin: string;
  createdAt: string;
  updatedAt: string;
  expectedDelivery: string;
  estimatedCost: number;
}

enum ImportStatus {
  OrderPlaced = 'Order Placed',
  InTransit = 'In Transit',
  AtPort = 'At Port',
  CargoReady = 'Cargo Ready',
  CargoDelivered = 'Cargo Delivered',
}

interface ExchangeRates {
  [currency: string]: number;
}

const DashboardPage = ({ shipments, onNavigate }) => {
    const [rates, setRates] = useState<ExchangeRates | null>(null);
    const [searchParams, setSearchParams] = useSearchParams();

    useEffect(() => {
        // ... existing fetchRates ...
    }, []);

    const kpiData = useMemo(() => {
        // ... existing kpiData logic ...
    }, [shipments, rates]);

    const shipmentStatusData = useMemo(() => {
        const statusCounts = {
            [ImportStatus.OrderPlaced]: 0,
            [ImportStatus.InTransit]: 0,
            [ImportStatus.AtPort]: 0,
            [ImportStatus.CargoReady]: 0,
            [ImportStatus.CargoDelivered]: 0,
        };

        shipments.forEach((shipment) => {
            if (statusCounts[shipment.status] !== undefined) {
                statusCounts[shipment.status]++;
            }
        });

        const labels = Object.keys(statusCounts) as ImportStatus[];
        const data = Object.values(statusCounts);
        const colors = [
            '#CCCCCC', // Order Placed
            '#6495ED', // In Transit
            '#DC143C', // At Port
            '#FFD700', // Cargo Ready
            '#32CD32', // Cargo Delivered
        ];

        return {
            labels,
            datasets: [
                {
                    data,
                    backgroundColor: colors,
                    hoverOffset: 4,
                },
            ],
        };
    }, [shipments]);

    const onSegmentClick = (segment) => {
        if (!segment) return;
        const statusLabel = segment.label as ImportStatus;
        const statusFilter = statusLabel;
        onNavigate(`/imports?status=${statusFilter}`);
    };

    const doughnutChartOptions = {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
            legend: {
                position: 'bottom',
                labels: {
                    usePointStyle: true,
                    boxWidth: 8,
                },
            },
            title: {
                display: false,
                text: 'Shipment Status',
            },
        },
    };

    return (
        <div className="dashboard-page">
            <h2>Dashboard</h2>
            <div className="dashboard-grid">
                {/* KPI Cards */}
                {kpiData.map((kpi) => (
                    <div key={kpi.label} className="dashboard-card kpi-card">
                        <div className="kpi-label">{kpi.label}</div>
                        <div className="kpi-value">{kpi.value}</div>
                    </div>
                ))}

                {/* Shipment Status Display */}
                <div className="dashboard-card chart-card">
                    <Doughnut
                        data={shipmentStatusData}
                        options={doughnutChartOptions}
                        onClick={(e) => {
                            const segment = e.chart.getElementsAtEvent(e)[0];
                            onSegmentClick(segment);
                        }}
                    />
                </div>
            </div>
        </div>
    );
};

export default DashboardPage;
```
