    onSegmentClick?: ((title: string, shipments: Shipment[]) => void) | null;
    size?: number;
    strokeWidth?: number;
}

const DoughnutChart = ({ title, data, onSegmentClick = null, size = 120, strokeWidth = 15 }: DoughnutChartProps) => {
    const total = useMemo(() => data.reduce((sum, item) => sum + (item.value || 0), 0), [data]);
    const sortedData = useMemo(() => data.filter(d => d.value > 0).sort((a, b) => b.value - a.value), [data]);
    const radius = (size / 2) - strokeWidth;
    const circumference = 2 * Math.PI * radius;
    let offset = 0;

    return (
        <div className="chart-wrapper-full">
            <h4 className="doughnut-title">{title}</h4>
            <div className="doughnut-chart-container">
                <svg className="doughnut-chart-svg" width={size} height={size} viewBox={'0 0 ' + size + ' ' + size}>
                    <circle className="doughnut-track" cx={size / 2} cy={size / 2} r={radius} strokeWidth={strokeWidth} />
                    {sortedData.map((item) => {
                        const percentage = total > 0 ? (item.value / total) : 0;
                        const segmentLength = circumference * percentage;
                        const currentOffset = offset;
                        offset += segmentLength;
                        return (
                            <circle
                                key={item.label}
                                className="doughnut-segment"
                                cx={size / 2} cy={size / 2} r={radius}
                                strokeDasharray={segmentLength + ' ' + circumference}
                                strokeDashoffset={-currentOffset}
                                stroke={item.color}
                                strokeWidth={strokeWidth}
                                style={{ cursor: onSegmentClick ? 'pointer' : 'default' }}
                                onClick={() => onSegmentClick && onSegmentClick(item.label, item.shipments)}
                            >
                                <title>{item.label}: {item.value}</title>
                            </circle>
                        );
                    })}
                     <text x={size / 2} y={size / 2} className="doughnut-total" dy=".3em">{total}</text>
                </svg>
                <div className="doughnut-chart-info">
                     <ul className="doughnut-legend">
                        {sortedData.map(item => {
                            const percentage = total > 0 ? (item.value / total * 100).toFixed(0) : 0;
                            return (
                                <li key={item.label}>
                                    <button
                                        className="legend-button"
                                        onClick={() => onSegmentClick && onSegmentClick(item.label, item.shipments)}
                                        disabled={!onSegmentClick}
                                    >
                                        <div className="legend-group">
                                            <span className="legend-marker" style={{ backgroundColor: item.color }}></span>
                                            <span className="legend-label">{item.label}</span>
                                        </div>
                                        <span className="legend-value">
                                            {item.value} ({percentage}%)
                                        </span>
                                    </button>
                                </li>
                            );
                        })}
                    </ul>
                </div>
            </div>
        </div>
    );
};

interface HorizontalBarChartProps {
    title: string;
    data: {label: string, value: number, shipments: Shipment[]}[];
    onBarClick?: ((title: string, shipments: Shipment[]) => void) | null;
    colorMap: { [key: string]: string };
}

const HorizontalBarChart = ({ title, data, onBarClick = null, colorMap }: HorizontalBarChartProps) => {
    const totalValue = useMemo(() => data.reduce((sum, item) => sum + (item.value || 0), 0), [data]);
    const sortedData = useMemo(() => data.filter(d => d.value > 0).sort((a, b) => b.value - a.value), [data]);

    return (
        <div className="chart-wrapper-full h-bar-chart-card">
            <h4 className="h-bar-chart-title">{title}</h4>
            <div className="h-bar-chart-body">
                {sortedData.map(item => {
                    const percentage = totalValue > 0 ? (item.value / totalValue) * 100 : 0;
                    return (
                        <button
                            key={item.label}
                            className="h-bar-item"
                            onClick={() => onBarClick && onBarClick(item.label, item.shipments)}
                            disabled={!onBarClick}
                        >
                            <span className="h-bar-label" title={item.label}>{item.label}</span>
                            <div className="h-bar-wrapper">
                                <div
                                    className="h-bar-segment"
                                    style={{ width: percentage + '%', backgroundColor: colorMap[item.label] || 'var(--kpi-accent-blue)' }}
                                ></div>
                                <span className="h-bar-value">{item.value.toLocaleString('en-US', { maximumFractionDigits: 2 })}</span>
                            </div>
                        </button>
                    );
                })}
            </div>
        </div>
    );
};

interface LineChartProps {
  title: string;
  subtitle: string;
  data: Array<{value: number, shipments: Shipment[]}>;
  labels: string[];
  goal?: number;
  color: string;
  onMaximize?: (() => void) | null;
  onPointClick?: ((title: string, shipments: Shipment[]) => void) | null;
}

const LineChart = ({ title, subtitle, data, labels, goal, color, onMaximize = null, onPointClick = null }: LineChartProps) => {
    const [tooltip, setTooltip] = useState(null);
    const containerRef = useRef(null);

    // Simple layout calculations
    const width = 400;
    const height = 200;
    const margin = { top: 20, right: 20, bottom: 30, left: 30 };
    const innerWidth = width - margin.left - margin.right;
    const innerHeight = height - margin.top - margin.bottom;

    const { linePath, areaPath, points } = useMemo(() => {
        if (!data || data.length === 0) return { linePath: '', areaPath: '', points: [] };

        const yMax = Math.max(...data.map(d => d.value), goal || 0) * 1.1 || 10;
        const yMin = 0;
        const yRange = yMax - yMin || 1; // Avoid division by zero

        const xScale = (index) => (index / (data.length > 1 ? data.length - 1 : 1)) * innerWidth;
        const yScale = (value) => innerHeight - ((value - yMin) / yRange) * innerHeight;

        const pointsArr = data.map((d, i) => ({
            x: xScale(i),
            y: yScale(d.value),
            value: d.value,
            label: labels[i],
            shipments: d.shipments
        }));

        const line = pointsArr.map((p, i) => (i === 0 ? 'M' : 'L') + ' ' + p.x + ' ' + p.y).join(' ');
        const area = line + ' V ' + innerHeight + ' H ' + pointsArr[0].x + ' Z';

        return { linePath: line, areaPath: area, points: pointsArr };
    }, [data, labels, innerWidth, innerHeight, goal]);

    return (
        <div className={'chart-wrapper-full line-chart-card ' + (onMaximize ? 'clickable' : '')} onClick={onMaximize}>
            <div className="line-chart-header">
                <div>
                    <h4>{title}</h4>
                    <p>{subtitle}</p>
                </div>
            </div>
            <div className="line-chart-container" ref={containerRef}>
                <svg className="line-chart-svg" viewBox={`0 0 ${width} ${height}`}>
                    <g transform={'translate(' + margin.left + ',' + margin.top + ')'}>
                        {/* Grid */}
                        {Array.from({ length: 5 }).map((_, i) => (
                            <line key={i} x1="0" x2={innerWidth} y1={i * innerHeight / 4} y2={i * innerHeight / 4} stroke="#e5e7eb" strokeWidth="1" />
                        ))}
                        {/* Goal Line */}
                        {goal && (
                             <line className="line-chart-goal" x1="0" x2={innerWidth} 
                                y1={innerHeight - ((goal / (Math.max(...data.map(d => d.value), goal) * 1.1 || 10)) * innerHeight)} 
                                y2={innerHeight - ((goal / (Math.max(...data.map(d => d.value), goal) * 1.1 || 10)) * innerHeight)} 
                             />
                        )}
                        <path className="line-chart-area" d={areaPath} style={{ fill: color, opacity: 0.1 }} />
                        <path className="line-chart-line" d={linePath} style={{ stroke: color, fill: 'none', strokeWidth: 2 }} />
                        {points.map((p, i) => (
                            <g key={i} onClick={(e) => { e.stopPropagation(); onPointClick && onPointClick(title + ' in ' + p.label, p.shipments); }}>
                                <circle cx={p.x} cy={p.y} r={4} fill={color} style={{cursor: 'pointer'}} />
                                <text x={p.x} y={p.y - 10} textAnchor="middle" fontSize="10">{p.value}</text>
                            </g>
                        ))}
                    </g>
                </svg>
            </div>
        </div>
    );
};

interface VerticalBarChartProps {
    title: string;
    data: {
        labels: string[];
        datasets: {
            label: string;
            data: number[];
            terminals?: string[];
            shipments?: Shipment[][];
        }[];
    };
    onSegmentClick?: ((title: string, shipments: Shipment[]) => void) | null;
}

const VerticalBarChart = ({ title, data, onSegmentClick = null }: VerticalBarChartProps) => {
    if (!data || !data.datasets || data.datasets.length === 0) return <div className="no-data-message">No data for {title}</div>;
    const { labels, datasets } = data;
    const totals = labels.map((_, i) => datasets.reduce((sum: number, ds) => sum + (ds.data[i] || 0), 0));
    const maxTotal = Math.max(...totals) * 1.1 || 10;

    return (
        <div className="chart-wrapper-full v-bar-chart-card">
            <h4 className="v-bar-chart-title">{title}</h4>
            <div className="v-bar-chart-container" style={{ gridTemplateColumns: 'repeat(' + labels.length + ', 1fr)' }}>
                {labels.map((label: string, i) => (
                    <div key={label} className="v-bar-group">
                        <div className="v-bar-total">{totals[i]}</div>
                        <div className="v-bar-stack" style={{ height: '150px' }}>
                            {datasets.map(ds => {
                                const value = ds.data[i] || 0;
                                if (value === 0) return null;
                                const height = maxTotal > 0 ? (value / maxTotal) * 100 : 0;
                                const terminal = ds.terminals ? ds.terminals[i] : ds.label;
                                const shipments = ds.shipments ? ds.shipments[i] : [];
                                return (
                                    <button
                                        key={ds.label + '-' + i}
                                        className="v-bar-segment"
                                        onClick={() => onSegmentClick && onSegmentClick(ds.label + ' in ' + label, shipments)}
                                        disabled={!onSegmentClick}
                                        style={{ height: height + '%', backgroundColor: TERMINAL_COLOR_MAP[terminal] || '#6b7280' }}
                                        title={terminal + ': ' + value}
                                    ></button>
                                );
                            })}
                        </div>
                        <span className="v-bar-label">{label}</span>
                    </div>
                ))}
            </div>
             {title === 'Cargo Volume' && (
                <div className="v-bar-legend">
                    {Object.entries(TERMINAL_COLOR_MAP).map(([label, color]) => (
                        <div key={label} className="v-bar-legend-item">
                            <span className="legend-marker" style={{ backgroundColor: color }}></span>
                            <span>{label}</span>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

