const DashboardPage = ({ shipments, onNavigate }) => {
    const [rates, setRates] = useState<ExchangeRates | null>(null);

    useEffect(() => {
        const fetchRates = async () => {
            try {
                const response = await fetch('https://economia.awesomeapi.com.br/json/last/USD-BRL,EUR-BRL,CNY-BRL');
                const data = await response.json();
                const now = new Date();
                setRates({
                    date: now.toLocaleDateString('pt-BR'),
                    time: now.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit'}),
                    usd: { compra: parseFloat(data.USDBRL.bid), venda: parseFloat(data.USDBRL.ask) },
                    eur: { compra: parseFloat(data.EURBRL.bid), venda: parseFloat(data.EURBRL.ask) },
                    cny: parseFloat(data.CNYBRL.bid)
                });
            } catch (error) { console.error(error); }
        };
        fetchRates();
    }, []);

    const kpiData = useMemo(() => {
        const now = new Date();
        const thirtyDaysAgo = new Date(now.getFullYear(), now.getMonth(), now.getDate() - 30);
        const recentShipments = shipments.filter(s => s.actualEta && new Date(s.actualEta) > thirtyDaysAgo);
        const totalValueRecent = recentShipments.reduce((sum: number, s) => sum + (s.invoiceValue || 0), 0);
        const totalDelivered = shipments.filter(s => s.status === 'CARGO DELIVERED').length;
        const onTimeShipments = shipments.filter(s => s.status === 'CARGO DELIVERED' && s.actualEta && s.lastTruckDelivery && new Date(s.lastTruckDelivery) <= new Date(s.actualEta)).length;

        return {
            totalValue: totalValueRecent,
            onTime: totalDelivered > 0 ? (onTimeShipments / totalDelivered * 100).toFixed(0) : '0',
            inTransit: shipments.filter(s => s.status === 'IN TRANSIT').length,
            totalShipments: shipments.length
        };
    }, [shipments]);

    const shipmentStatusData = useMemo(() => {
         const config = [
            { status: ImportStatus.OrderPlaced, label: 'Order Placed', color: '#6c757d' },
            { status: ImportStatus.InProgress, label: 'In Transit', color: '#3b82f6' },
            { status: ImportStatus.AtPort, label: 'At Port', color: '#ef4444' },
            { status: ImportStatus.CargoReady, label: 'Cargo Ready', color: '#f59e0b' },
            { status: ImportStatus.Delivered, label: 'Delivered', color: '#10b981' }
        ];
        return config.map(c => ({
            label: c.label,
            value: shipments.filter(s => s.status === c.status).length,
            shipments: shipments.filter(s => s.status === c.status),
            color: c.color
        }));
    }, [shipments]);

    return (
        <div className="dashboard-page">
             <div className="page-header"><DashboardIcon /><h1>Dashboard</h1></div>
             <div className="kpi-grid">
                <div className="kpi-card"><div className="kpi-title">Total Shipments</div><div className="kpi-value">{kpiData.totalShipments}</div></div>
                <div className="kpi-card"><div className="kpi-title">In Transit</div><div className="kpi-value">{kpiData.inTransit}</div></div>
                <div className="kpi-card"><div className="kpi-title">On-Time Delivery</div><div className="kpi-value">{kpiData.onTime}%</div></div>
                <div className="kpi-card"><div className="kpi-title">Value (30d)</div><div className="kpi-value">{kpiData.totalValue.toLocaleString('en-US', { style: 'currency', currency: 'USD' })}</div></div>
            </div>
            <div className="dashboard-grid">
                <div className="dashboard-card chart-card">
                     <DoughnutChart title="Shipment Status" data={shipmentStatusData} onSegmentClick={(lbl) => onNavigate('Imports', {statusFilter: lbl === 'In Transit' ? ImportStatus.InProgress : lbl})} size={220} strokeWidth={25} />
                </div>
                <div className="dashboard-card">
                    <h3 className="card-title">Exchange Rates</h3>
                    {rates ? (
                        <div className="rates-grid">
                            <strong>USD</strong> <span>{rates.usd.compra.toFixed(4)}</span>
                            <strong>EUR</strong> <span>{rates.eur.compra.toFixed(4)}</span>
                            <strong>CNY</strong> <span>{rates.cny.toFixed(4)}</span>
                        </div>
                    ) : <LoadingSpinner />}
                </div>
            </div>
        </div>
    );
};

