interface KpiFilters { cargo: string[]; year: number | 'All'; }
interface KPIPageProps { shipments: Shipment[]; onFilterChange: (type: keyof KpiFilters, val: any) => void; filters: KpiFilters; }

const KPIFilterSidebar = ({ shipments, onFilterChange, activeFilters }: { shipments: Shipment[]; onFilterChange: any; activeFilters: KpiFilters; }) => {
    const cargoTypes = useMemo(() => Array.from(new Set(shipments.map(s => s.typeOfCargo).filter(Boolean))).sort(), [shipments]);
    const years = useMemo(() => Array.from(new Set(shipments.map(s => s.actualEta ? new Date(s.actualEta).getFullYear() : null).filter(y => y))).sort((a, b) => b - a), [shipments]);

    const toggleCargo = (type) => {
        const current = activeFilters.cargo || [];
        onFilterChange('cargo', current.includes(type) ? current.filter(c => c !== type) : [...current, type]);
    };

    return (
        <aside className="kpi-dashboard-sidebar">
            <div className="kpi-filter-box">
                <h4>Year</h4>
                <div className="cargo-filter-list">
                    <button onClick={() => onFilterChange('year', 'All')} className={activeFilters.year === 'All' ? 'active' : ''}>All</button>
                    {years.map(y => <button key={y} onClick={() => onFilterChange('year', y)} className={activeFilters.year === y ? 'active' : ''}>{y}</button>)}
                </div>
            </div>
            <div className="kpi-filter-box">
                <h4>Cargo</h4>
                <div className="cargo-filter-list">
                    <button onClick={() => onFilterChange('cargo', [])} className={activeFilters.cargo.length === 0 ? 'active' : ''}>Clear</button>
                    {cargoTypes.map(t => <button key={t} onClick={() => toggleCargo(t)} className={activeFilters.cargo.includes(t) ? 'active' : ''}>{t}</button>)}
                </div>
            </div>
        </aside>
    );
};

const CargosInTransitDashboard = ({ shipments, onFilterChange, filters }: KPIPageProps) => {
    const [selected, setSelected] = useState<{title: string, data: Shipment[]} | null>(null);

    const filtered = useMemo(() => shipments.filter(s => {
        const cm = !filters.cargo.length || filters.cargo.includes(s.typeOfCargo);
        const ym = filters.year === 'All' || (s.actualEta && new Date(s.actualEta).getFullYear() === filters.year);
        return cm && ym;
    }), [shipments, filters]);

    const handleClick = (title, data) => setSelected({ title, data });

    const chartData = useMemo(() => {
        const groupBy = (field, colors) => {
            const g = {};
            filtered.forEach(s => { const k = s[field] || 'Unknown'; if (!g[k]) g[k] = []; g[k].push(s); });
            return Object.entries(g).map(([l, d]: [string, any[]]) => ({ label: l, value: d.length, shipments: d, color: colors[l] || '#9ca3af' }));
        };
        return {
            incoterm: groupBy('incoterm', { 'CIF': '#8b5cf6', 'FOB': '#3b82f6', 'DAP': '#ec4899' }),
            status: groupBy('status', { 'DOCUMENT REVIEW': '#f97316', 'IN TRANSIT': '#3b82f6', 'AT THE PORT': '#ef4444' }),
            sap: filtered.reduce((acc, s) => { s.poSap ? acc.ok.push(s) : acc.pending.push(s); return acc; }, {ok:[], pending:[]}),
            doc: filtered.reduce((acc, s) => { s.approvedDraftDi === 'OK' ? acc.ok.push(s) : acc.no.push(s); return acc; }, {ok:[], no:[]})
        };
    }, [filtered]);

    return (
        <div className="cargos-in-transit-grid">
            <KPIFilterSidebar shipments={shipments} onFilterChange={onFilterChange} activeFilters={filters} />
            <main className="kpi-dashboard-main-grid">
                <div className="kpi-main-charts">
                    <DoughnutChart title="Incoterms" data={chartData.incoterm} onSegmentClick={handleClick} />
                    <DoughnutChart title="Status" data={chartData.status} onSegmentClick={handleClick} />
                    <DoughnutChart title="SAP PO" data={[{label:'OK', value: chartData.sap.ok.length, color:'#10b981', shipments: chartData.sap.ok}, {label:'Pending', value: chartData.sap.pending.length, color:'#ef4444', shipments: chartData.sap.pending}]} onSegmentClick={handleClick} />
                    <DoughnutChart title="Doc Status" data={[{label:'Approved', value: chartData.doc.ok.length, color:'#10b981', shipments: chartData.doc.ok}, {label:'Pending', value: chartData.doc.no.length, color:'#ef4444', shipments: chartData.doc.no}]} onSegmentClick={handleClick} />
                </div>
                {selected && <ShipmentsTable title={selected.title} shipments={selected.data} onClose={() => setSelected(null)} />}
            </main>
        </div>
    );
};

