        return (filters.year === 'All' || d.getFullYear().toString() === filters.year) &&
               (filters.month === 'All' || (d.getMonth() + 1).toString() === filters.month) &&
               (filters.analyst === 'All' || (s.technicianResponsibleBrazil || '').toLowerCase() === filters.analyst.toLowerCase()) &&
               (filters.cargo === 'All' || s.typeOfCargo === filters.cargo);
    }), [shipments, filters]);

    const metrics = useMemo(() => {
        const dis = new Set(filtered.map(s => s.di).filter(Boolean));
