                <KPIMetricCard icon={<ReceiptIcon />} title="Total DIs" value={metrics.totalDIs} />
                <KPIMetricCard icon={<UserIcon />} title="DIs / Analyst" value={metrics.disPerAnalyst} />
                <div className="chart-wrapper-full">
                    <HorizontalBarChart title="Volume by Mode" data={volByMode} onBarClick={(t, s) => setSelected({title: t, data: s})} colorMap={{'FCL':'#007bff', 'LCL':'#28a745', 'AIR':'#17a2b8'}} />
