        // FIX: Explicitly type the accumulator in the reduce function to ensure type safety during arithmetic operations.
        const totalValueRecent = recentShipments.reduce((sum: number, s) => sum + (s.invoiceValue || 0), 0);
        const onTimeShipments = shipments.filter(s => s.status === 'CARGO DELIVERED' && s.actualEta && s.lastTruckDelivery && new Date(s.lastTruckDelivery) <= new Date(s.actualEta)).length;
        const totalDelivered = shipments.filter(s => s.status === 'CARGO DELIVERED').length;
        const onTimePercentage = totalDelivered > 0 ? (onTimeShipments / totalDelivered * 100).toFixed(0) : '0';
        const inTransitCount = shipments.filter(s => s.status === 'IN TRANSIT').length;

        return {
            totalValue: totalValueRecent,
            onTime: onTimePercentage,
            inTransit: inTransitCount,
            totalShipments: shipments.length
        };
    }, [shipments]);

    const actionItems = useMemo(() => {
        const todayStr = new Date().toISOString().split('T')[0];
        // Simple logic: Arriving today if actualEta matches today
        const arrivingToday = shipments.filter(s => {
            if (!s.actualEta) return false;
            // Ensure we compare YYYY-MM-DD
            return s.actualEta.split('T')[0] === todayStr;
        }).length;

        // Documents pending: Generic status check
        const docsPending = shipments.filter(s => 
            s.status === ImportStatus.DocumentReview || 
            (s.status === ImportStatus.DiRegistered && (!s.approvedDraftDi || s.approvedDraftDi !== 'OK'))
        ).length;

        return { arrivingToday, docsPending };
    }, [shipments]);

    const shipmentStatusData = useMemo(() => {
        // Explicit statuses requested by user
        // Sum 'Cargo Ready' into 'At Port'
        const statusConfig = [
            { 
                label: 'Order Placed', 
                statuses: [ImportStatus.OrderPlaced], 
                color: '#6c757d' 
            },
            { 
                label: 'In Transit', 
                statuses: [ImportStatus.InProgress], 
                color: '#3b82f6' 
            },
            { 
                label: 'At Port', 
                statuses: [ImportStatus.AtPort, ImportStatus.CargoReady], 
                color: '#ef4444' 
            },
            { 
                label: 'Delivered', 
                statuses: [ImportStatus.Delivered], 
                color: '#10b981' 
            }
        ];

        return statusConfig.map(config => {
            const matching = shipments.filter(s => s.status && config.statuses.includes(s.status as ImportStatus));
            return {
                label: config.label,
                value: matching.length,
                shipments: matching,
                color: config.color
            };
        });
    }, [shipments]);


    const handleSegmentClick = (label, filteredShipments) => {
        // Map the readable label back to the status enum for the filter
        let statusFilter = 'All';
        if (label === 'Order Placed') statusFilter = ImportStatus.OrderPlaced;
        if (label === 'In Transit') statusFilter = ImportStatus.InProgress;
        // For 'At Port', we map to the primary At Port enum. 
        // Note: In strict filter mode this excludes 'Cargo Ready', but is consistent with available filters.
        if (label === 'At Port') statusFilter = ImportStatus.AtPort;
        if (label === 'Delivered') statusFilter = ImportStatus.Delivered;

        onNavigate('Imports', { statusFilter });
    };

    return (
        <div className="dashboard-page">
             <div className="page-header">
                <DashboardIcon />
                <h1>Dashboard</h1>
            </div>
            <p className="page-subtitle">Overview of your import operations.</p>

            <div className="kpi-grid">
                 <div className="kpi-card">
                    <div>
                        <div className="kpi-title">Total Shipments</div>
                        <div className="kpi-value">{kpiData.totalShipments}</div>
                    </div>
                </div>
                <div className="kpi-card">
                    <div>
                        <div className="kpi-title">In Transit</div>
                        <div className="kpi-value">{kpiData.inTransit}</div>
                    </div>
                </div>
                <div className="kpi-card">
                    <div>
                        <div className="kpi-title">On-Time Delivery</div>
                        <div className="kpi-value">{kpiData.onTime}<span className="kpi-unit">%</span></div>
                    </div>
                </div>
                <div className="kpi-card">
                    <div>
                        <div className="kpi-title">Value (Last 30d)</div>
                        <div className="kpi-value">{kpiData.totalValue.toLocaleString('en-US', { style: 'currency', currency: 'USD' })}</div>
                    </div>
                </div>
            </div>

            <div className="dashboard-grid">
                <div className="dashboard-card chart-card">
                     <DoughnutChart 
                        title="Shipment Status" 
                        data={shipmentStatusData} 
                        onSegmentClick={handleSegmentClick} 
                        size={220}
                        strokeWidth={25}
                    />
                </div>
                <div className="dashboard-card">
                    <h3 className="card-title">Action Items</h3>
                    <div className="rates-content">
                        <p className="rates-updated">Highlights for today</p>
                        <div className="rates-grid">
                            <strong style={{color: '#3b82f6'}}>Arriving Today</strong> <span>{actionItems.arrivingToday} shipments</span>
                            <strong style={{color: '#f97316'}}>Pending Docs</strong> <span>{actionItems.docsPending} items</span>
