    const selectStyle = { padding: '0.5rem', borderRadius: '4px', border: '1px solid var(--border-color)', background: 'var(--card-bg)', color: 'var(--text-color)' };
    const groupStyle = { display: 'flex', flexDirection: 'column' as 'column', gap: '0.25rem' };

    return (
