    return (
        <div className="kpis-page">
            <header className="kpi-dashboard-header">
                <div className="kpi-dashboard-title">
                     <h1>INTERNATIONAL TRADE - DIVISION 11</h1>
                     <h2>{activeTab.toUpperCase()}</h2>
