                                    <td>
                                        <span className="bl-cell" style={{fontWeight: 600}}>{s.blAwb}</span>
                                        {s.poSap && <div className="po-sub" style={{fontSize: '0.8em', opacity: 0.7}}>{s.poSap}</div>}
                                    </td>
                                    <td>
                                        <span className={`status-badge status-${(s.status || '').replace(/\s+/g, '-').toLowerCase()}`}>
