            }

            if (groups.hasOwnProperty(param)) {
                const group = groups[param as keyof typeof groups];
                group.shipments.push(s);
                if (s.di) {
                    group.uniqueDIs.add(s.di);
                }
            } else {
                 // Catch any unmatched as N/A
                 groups['N/A'].shipments.push(s);
                 if (s.di) groups['N/A'].uniqueDIs.add(s.di);
            }
        });

        return Object.entries(groups).map(([label, data]) => ({
            label,
            value: data.uniqueDIs.size,
            secondaryValue: data.shipments.length,
            shipments: data.shipments,
            color: { 'Green': '#28a745', 'Yellow': '#ffc107', 'Red': '#dc3545', 'N/A': '#6b7280' }[label]
