import { BrokerProcess, BrokerKpiData, BrokerChartData } from '../types';
import * as XLSX from 'xlsx';

// Helper to parse dates (handles Excel serial numbers and strings)
const parseDate = (dateInput: any): Date | null => {
    if (!dateInput) return null;
    if (dateInput instanceof Date) return dateInput;
    if (typeof dateInput === 'number') {
        const utc_days = Math.floor(dateInput - 25569);
        const utc_value = utc_days * 86400;
        return new Date(utc_value * 1000);
    }
    if (typeof dateInput === 'string') {
        const ddmmyyyy = dateInput.trim().match(/^(\d{1,2})[\/\-\.](\d{1,2})[\/\-\.](\d{4})/);
        if (ddmmyyyy) return new Date(parseInt(ddmmyyyy[3]), parseInt(ddmmyyyy[2])-1, parseInt(ddmmyyyy[1]));
        const d = new Date(dateInput);
        if (!isNaN(d.getTime())) return d;
    }
    return null;
};

const diffDays = (d1: Date | null, d2: Date | null) => {
    if (!d1 || !d2) return null;
    return Math.floor((d2.getTime() - d1.getTime()) / (1000 * 60 * 60 * 24));
};

export const processBrokerData = (data: any[][]): { processes: BrokerProcess[], importers: string[], channels: string[] } => {
    // 1. Find Header
    const headerRowIndex = data.findIndex(row => 
        row.some(cell => String(cell).toUpperCase().includes('DI') || String(cell).toUpperCase().includes('DECLARAÇÃO'))
    );
    if (headerRowIndex === -1) throw new Error("Could not find header row with 'DI' or 'DECLARAÇÃO'");

    const headers = data[headerRowIndex].map(h => String(h).toUpperCase().trim());

    // 2. Map Columns (Flexible matching for Portuguese/English)
    const idx = {
        ref: headers.findIndex(h => h.includes('REF') || h.includes('PROCESSO')),
        importer: headers.findIndex(h => h.includes('IMPORTADOR') || h.includes('CLIENTE') || h.includes('IMPORTER')),
        bl: headers.findIndex(h => h.includes('BL') || h.includes('BILL OF LADING') || h.includes('MASTER')),
        di: headers.findIndex(h => h.includes('DI') || h.includes('DECLARACAO') || h.includes('NUMERO')),
        arrival: headers.findIndex(h => h.includes('CHEGADA') || h.includes('ARRIVAL') || h.includes('ATA')),
        register: headers.findIndex(h => h.includes('REGISTRO') || h.includes('DATA DI')),
        clearance: headers.findIndex(h => h.includes('DESEMBARACO') || h.includes('CI') || h.includes('CLEARANCE')),
        channel: headers.findIndex(h => h.includes('CANAL') || h.includes('PARAMETRIZACAO') || h.includes('CHANNEL')),
        cif: headers.findIndex(h => h.includes('CIF') || h.includes('VALOR ADUANEIRO')),
        taxes: headers.findIndex(h => h.includes('IMPOSTOS') || h.includes('TOTAL TRIBUTOS') || h.includes('TAXES')),
    };

    // 3. Process Rows
    const importers = new Set<string>();
    const channels = new Set<string>();

    const processes = data.slice(headerRowIndex + 1).map((row, i) => {
        if (!row || row.length === 0) return null;

        const importer = idx.importer !== -1 ? String(row[idx.importer] || 'Unknown').trim() : 'Unknown';
        const rawChannel = idx.channel !== -1 ? String(row[idx.channel] || 'A AGUARDAR').toUpperCase().trim() : 'A AGUARDAR';

        let channel: BrokerProcess['channel'] = 'A AGUARDAR';
        if (rawChannel.includes('VERDE') || rawChannel.includes('GREEN')) channel = 'VERDE';
        else if (rawChannel.includes('AMARELO') || rawChannel.includes('YELLOW')) channel = 'AMARELO';
        else if (rawChannel.includes('VERMELHO') || rawChannel.includes('RED')) channel = 'VERMELHO';
        else if (rawChannel.includes('CINZA') || rawChannel.includes('GRAY')) channel = 'CINZA';

        const arrivalDate = parseDate(row[idx.arrival]);
        const registrationDate = parseDate(row[idx.register]);
        const clearanceDate = parseDate(row[idx.clearance]);

        importers.add(importer);
        channels.add(channel);

        return {
            processNumber: idx.ref !== -1 ? String(row[idx.ref]) : `P-${i}`,
            importer,
            blNumber: idx.bl !== -1 ? String(row[idx.bl]) : '',
            diNumber: idx.di !== -1 ? String(row[idx.di]) : '',
            containerType: 'General', // Placeholder if not in excel
            arrivalDate,
            registrationDate,
            clearanceDate,
            channel,
            cifValue: idx.cif !== -1 ? Number(row[idx.cif]) || 0 : 0,
            taxes: idx.taxes !== -1 ? Number(row[idx.taxes]) || 0 : 0,

            // Calculated Logic
            leadTimeArrivalToRegister: diffDays(arrivalDate, registrationDate),
            leadTimeRegisterToClear: diffDays(registrationDate, clearanceDate),
            totalLeadTime: diffDays(arrivalDate, clearanceDate)
        } as BrokerProcess;
    }).filter(Boolean) as BrokerProcess[];

    return { 
        processes, 
        importers: Array.from(importers).sort(), 
        channels: Array.from(channels).sort() 
    };
};

export const calculateBrokerStats = (processes: BrokerProcess[]): { kpis: BrokerKpiData, charts: BrokerChartData } => {
    const totalProcesses = processes.length;
    const totalCIF = processes.reduce((acc, p) => acc + p.cifValue, 0);
    const totalTaxes = processes.reduce((acc, p) => acc + p.taxes, 0);

    // Green Channel %
    const greenCount = processes.filter(p => p.channel === 'VERDE').length;
    const greenChannelPercentage = totalProcesses ? ((greenCount / totalProcesses) * 100).toFixed(1) : '0.0';

    // Lead Times
    const cleared = processes.filter(p => p.clearanceDate);
    const avgTotal = cleared.reduce((acc, p) => acc + (p.totalLeadTime || 0), 0) / (cleared.length || 1);
    const avgCustoms = cleared.reduce((acc, p) => acc + (p.leadTimeRegisterToClear || 0), 0) / (cleared.length || 1);

    // Chart: Channels
    const channelCounts = processes.reduce((acc, p) => {
        acc[p.channel] = (acc[p.channel] || 0) + 1;
        return acc;
    }, {} as Record<string, number>);

    const channelMapColor = { 'VERDE': '#16A34A', 'AMARELO': '#F59E0B', 'VERMELHO': '#DC2626', 'CINZA': '#374151', 'A AGUARDAR': '#9CA3AF' };

    const channelDistribution = Object.entries(channelCounts).map(([name, value]) => ({
        name, value, color: channelMapColor[name as keyof typeof channelMapColor] || '#000'
    }));

    // Chart: Daily Volume
    const dailyVol = processes.reduce((acc, p) => {
        if(!p.registrationDate) return acc;
        const dateKey = p.registrationDate.toISOString().split('T')[0];
        if(!acc[dateKey]) acc[dateKey] = { date: dateKey, count: 0, value: 0 };
        acc[dateKey].count++;
        acc[dateKey].value += p.cifValue;
        return acc;
    }, {} as Record<string, any>);

    const dailyVolume = Object.values(dailyVol).sort((a,b) => new Date(a.date).getTime() - new Date(b.date).getTime());

    // Chart: Importer Ranking
    const importerVol = processes.reduce((acc, p) => {
        acc[p.importer] = (acc[p.importer] || 0) + p.cifValue;
        return acc;
    }, {} as Record<string, number>);

    const importerRanking = Object.entries(importerVol)
        .map(([name, value]) => ({ name, value }))
        .sort((a, b) => b.value - a.value)
        .slice(0, 10);

    return {
        kpis: {
            totalProcesses,
            totalCIF,
            totalTaxes,
            greenChannelPercentage,
            avgLeadTimeTotal: avgTotal.toFixed(1),
            avgLeadTimeCustoms: avgCustoms.toFixed(1),
            pendingClearance: totalProcesses - cleared.length
        },
        charts: {
            channelDistribution,
            dailyVolume,
            importerRanking,
            leadTimeBreakdown: [
                { name: 'Arrival -> Register', value: parseFloat((avgTotal - avgCustoms).toFixed(1)) },
                { name: 'Register -> Clear (Customs)', value: parseFloat(avgCustoms.toFixed(1)) }
            ]
        }
    };
};
