const KPIFilterSidebar = ({ shipments, onFilterChange, activeFilters, dateSourceField = 'actualEta', isOpen, onToggle }: { shipments: Shipment[]; onFilterChange: (filterType: keyof KpiFilters, value: any) => void; activeFilters: KpiFilters; dateSourceField?: 'actualEta' | 'diRegistrationDate', isOpen: boolean, onToggle: () => void }) => {
    const cargoTypes = useMemo(() => {
        const types = new Set(shipments.map(s => s.typeOfCargo).filter(Boolean));
        return Array.from(types).sort();
    }, [shipments]);

    const years = useMemo(() => {
        const yearSet = new Set(
            shipments
                .map(s => {
                    const dateString = dateSourceField === 'diRegistrationDate' ? s.diRegistrationDate : s.actualEta;
                    if (!dateString) return null;
                    const date = new Date(dateString);
                    return isNaN(date.getTime()) ? null : date.getFullYear();
                })
                .filter(y => y && !isNaN(y))
        );
        return Array.from(yearSet).sort((a, b) => b - a);
    }, [shipments, dateSourceField]);

     const months = [
        { value: 0, label: 'Jan' }, { value: 1, label: 'Feb' }, { value: 2, label: 'Mar' },
        { value: 3, label: 'Apr' }, { value: 4, label: 'May' }, { value: 5, label: 'Jun' },
        { value: 6, label: 'Jul' }, { value: 7, label: 'Aug' }, { value: 8, label: 'Sep' },
        { value: 9, label: 'Oct' }, { value: 10, label: 'Nov' }, { value: 11, label: 'Dec' }
    ];

    const handleCargoClick = (cargoType) => {
        const currentSelection = activeFilters.cargo || [];
        const newSelection = currentSelection.includes(cargoType)
            ? currentSelection.filter(c => c !== cargoType)
            : [...currentSelection, cargoType];
        onFilterChange('cargo', newSelection);
    };

    const handleClearCargo = () => {
        onFilterChange('cargo', []);
    };

    const handleYearClick = (year) => {
        onFilterChange('year', year);
    };

    const handleMonthClick = (monthValue: number) => {
        const currentMonths = activeFilters.month || [];
        let newMonths;
        if (currentMonths.includes(monthValue)) {
            newMonths = currentMonths.filter(m => m !== monthValue);
        } else {
            newMonths = [...currentMonths, monthValue];
        }
        onFilterChange('month', newMonths);
    };

    const handleAllMonthsClick = () => {
        onFilterChange('month', []);
    };

    return (
        <aside className={`kpi-dashboard-sidebar ${!isOpen ? 'collapsed' : ''}`}>
            <button className="kpi-sidebar-toggle" onClick={onToggle} aria-label="Toggle Filter Sidebar">
                <span className="material-symbols-outlined">{isOpen ? 'chevron_left' : 'chevron_right'}</span>
            </button>

            <div className="kpi-filter-box">
                <h4>Year</h4>
                <div className="cargo-filter-list">
                    <button onClick={() => handleYearClick('All')} className={activeFilters.year === 'All' ? 'active' : ''}>All Years</button>
                    {years.map(year => (
                        <button key={year} onClick={() => handleYearClick(year)} className={activeFilters.year === year ? 'active' : ''}>
                            {year}
                        </button>
                    ))}
                </div>
            </div>
            <div className="kpi-filter-box">
                <h4>Month</h4>
                <div className="month-filter-grid">
                     <button 
                        onClick={handleAllMonthsClick}
                        className={activeFilters.month.length === 0 ? 'active' : ''}
                        style={{gridColumn: '1 / -1'}}
                     >
                        All Months
                     </button>
                     {months.map(m => (
                        <button 
                            key={m.label} 
                            onClick={() => handleMonthClick(m.value)}
                            className={activeFilters.month.includes(m.value) ? 'active' : ''}
                        >
                            {m.label}
                        </button>
                    ))}
                </div>
            </div>
            <div className="kpi-filter-box">
