        const greenChannelPercentage = totalProcesses ? ((greenCount / totalProcesses) * 100).toFixed(1) : '0.0';

        // Lead Times
        // Customs Time: Register -> Clear
        const clearedShipments = filteredShipments.filter(s => s.diRegistrationDate && s.greenChannelOrDeliveryAuthorizedDate);
        const totalCustomsDays = clearedShipments.reduce((acc, s) => {
             const days = calculateDaysBetween(s.diRegistrationDate, s.greenChannelOrDeliveryAuthorizedDate);
             return acc + (days || 0);
        }, 0);
        const avgLeadTimeCustoms = clearedShipments.length ? (totalCustomsDays / clearedShipments.length).toFixed(1) : '0.0';

        // Charts Data
        // 1. Channel Distribution
        const channelCounts: Record<string, number> = {};
        filteredShipments.forEach(s => {
            let channel = 'A AGUARDAR';
            if (s.parametrization) {
                const p = s.parametrization.toUpperCase();
                if (p.includes('VERDE') || p.includes('GREEN')) channel = 'VERDE';
                else if (p.includes('AMARELO') || p.includes('YELLOW')) channel = 'AMARELO';
                else if (p.includes('VERMELHO') || p.includes('RED')) channel = 'VERMELHO';
                else if (p.includes('CINZA') || p.includes('GRAY')) channel = 'CINZA';
            }
            channelCounts[channel] = (channelCounts[channel] || 0) + 1;
        });

        const channelMapColor: Record<string, string> = { 'VERDE': '#22c55e', 'AMARELO': '#facc15', 'VERMELHO': '#ef4444', 'CINZA': '#6b7280', 'A AGUARDAR': '#94a3b8' };
        const channelDistribution = Object.entries(channelCounts).map(([name, value]) => ({
            label: name, value, shipments: [], color: channelMapColor[name] || '#000'
        }));

        // 2. Top Importers
        const importerVol: Record<string, number> = {};
        filteredShipments.forEach(s => {
            const imp = s.importer || 'Unknown';
