interface ChartProps {
    title: string;
    data: any;
    onSegmentClick?: any;
    size?: number;
    strokeWidth?: number;
    colorMap?: any;
    onBarClick?: any;
    labels?: any;
    goal?: number;
    color?: string;
    onMaximize?: any;
    onPointClick?: any;
    subtitle?: string;
}

const DoughnutChart = ({ title, data, onSegmentClick = null, size = 120, strokeWidth = 15 }: ChartProps) => {
    const total = useMemo(() => data.reduce((sum: number, item: any) => sum + item.value, 0), [data]);
    const sortedData = useMemo(() => data.filter((d: any) => d.value > 0).sort((a: any, b: any) => b.value - a.value), [data]);
    const radius = (size / 2) - strokeWidth;
    const circumference = 2 * Math.PI * radius;
    let offset = 0;

    return (
        <div className="chart-wrapper-full">
            <h4 className="doughnut-title">{title}</h4>
            <div className="doughnut-chart-container">
                <svg className="doughnut-chart-svg" width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
                    <circle className="doughnut-track" cx={size / 2} cy={size / 2} r={radius} strokeWidth={strokeWidth} />
                    {sortedData.map((item: any) => {
                        const percentage = total > 0 ? (item.value / total) : 0;
                        const segmentLength = circumference * percentage;
                        const currentOffset = offset;
                        offset += segmentLength;
                        return (
                            <circle key={item.label} className="doughnut-segment" cx={size / 2} cy={size / 2} r={radius}
                                strokeDasharray={`${segmentLength} ${circumference}`} strokeDashoffset={-currentOffset}
                                stroke={item.color} strokeWidth={strokeWidth} onClick={() => onSegmentClick && onSegmentClick(item.label, item.shipments)}
                                style={{cursor: onSegmentClick ? 'pointer' : 'default'}}
                            />
                        );
                    })}
                     <text x={size / 2} y={size / 2} className="doughnut-total" dy=".3em">{total}</text>
                </svg>
                <div className="doughnut-chart-info">
                     <ul className="doughnut-legend">
                        {sortedData.map((item: any) => {
                            const percentage = total > 0 ? (item.value / total * 100).toFixed(0) : 0;
                            return (
                                <li key={item.label}>
                                    <button className="legend-button" onClick={() => onSegmentClick && onSegmentClick(item.label, item.shipments)} disabled={!onSegmentClick}>
                                        <div className="legend-group">
                                            <span className="legend-marker" style={{ backgroundColor: item.color }}></span>
                                            <span className="legend-label">{item.label}</span>
                                        </div>
                                        <span className="legend-value">
                                            {title === 'DI Channel Parameterization' ? (item.value + (item.label === 'Red' && item.secondaryValue ? ` (${item.secondaryValue})` : '')) : `${item.value} (${percentage}%)`}
                                        </span>
                                    </button>
                                </li>
                            );
                        })}
                    </ul>
                </div>
            </div>
        </div>
    );
};

const HorizontalBarChart = ({ title, data, onBarClick = null, colorMap }: ChartProps) => {
    const totalValue = useMemo(() => data.reduce((sum: number, item: any) => sum + item.value, 0), [data]);
    const sortedData = useMemo(() => data.filter((d: any) => d.value > 0).sort((a: any, b: any) => b.value - a.value), [data]);

    return (
        <div className="chart-wrapper-full h-bar-chart-card">
            <h4 className="h-bar-chart-title">{title}</h4>
            <div className="h-bar-chart-body">
                {sortedData.map((item: any) => {
                    const percentage = totalValue > 0 ? (item.value / totalValue) * 100 : 0;
                    return (
                        <button key={item.label} className="h-bar-item" onClick={() => onBarClick && onBarClick(item.label, item.shipments)} disabled={!onBarClick}>
                            <span className="h-bar-label" title={item.label}>{item.label}</span>
                            <div className="h-bar-wrapper">
                                <div className="h-bar-segment" style={{ width: `${percentage}%`, backgroundColor: (colorMap && colorMap[item.label]) || 'var(--kpi-accent-blue)' }}></div>
                                <span className="h-bar-value">{item.value.toLocaleString('en-US', { maximumFractionDigits: 2 })}</span>
                            </div>
                        </button>
                    );
                })}
            </div>
        </div>
    );
};

const VerticalBarChart = ({ title, data, onSegmentClick = null }: ChartProps) => {
    if (!data || !data.datasets) return <div className="no-data-message">No data</div>;
    const { labels, datasets } = data;
    const totals = labels.map((_, i) => datasets.reduce((sum: number, ds: any) => sum + (ds.data[i] || 0), 0));
    const maxTotal = Math.max(...totals) * 1.1 || 10;
    const cargoVolumeLegend = useMemo(() => Object.entries(TERMINAL_COLOR_MAP).map(([label, color]) => ({ label, color })), []);

    return (
        <div className="chart-wrapper-full v-bar-chart-card">
            <h4 className="v-bar-chart-title">{title}</h4>
            <div className="v-bar-chart-container" style={{ gridTemplateColumns: `repeat(${labels.length}, 1fr)` }}>
                {labels.map((label: string, i: number) => (
                    <div key={label} className="v-bar-group">
                        <div className="v-bar-total">{totals[i]}</div>
                        <div className="v-bar-stack" style={{ height: '150px' }}>
                            {datasets.map((ds: any) => {
                                const value = ds.data[i] || 0;
                                if (value === 0) return null;
                                const height = maxTotal > 0 ? (value / maxTotal) * 100 : 0;
                                const terminal = ds.terminals ? ds.terminals[i] : ds.label;
                                return (
                                    <button key={`${ds.label}-${i}`} className="v-bar-segment"
                                        onClick={() => onSegmentClick && onSegmentClick(`${ds.label} in ${label}`, ds.shipments ? ds.shipments[i] : [])}
                                        style={{ height: `${height}%`, backgroundColor: TERMINAL_COLOR_MAP[terminal] || '#6b7280' }}
                                        title={`${terminal}: ${value}`}
                                    ></button>
                                );
                            })}
                        </div>
                        <span className="v-bar-label">{label}</span>
                    </div>
                ))}
            </div>
            {title === 'Cargo Volume' && (
                <div className="v-bar-legend">
                    {cargoVolumeLegend.map(item => (
                        <div key={item.label} className="v-bar-legend-item">
                            <span className="legend-marker" style={{ backgroundColor: item.color }}></span><span>{item.label}</span>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

const LineChart = ({ title, subtitle, data, labels, goal, color, onMaximize = null, onPointClick = null }: ChartProps) => {
    const [tooltip, setTooltip] = useState(null);
    const containerRef = useRef<HTMLDivElement>(null);

    const { width, height, margin } = useMemo(() => {
        return { width: 300, height: 150, margin: { top: 20, right: 20, bottom: 30, left: 30 } }; 
    }, []);

    const { linePath, areaPath, points } = useMemo(() => {
        if (!data || data.length === 0) return { linePath: '', areaPath: '', points: [] };
        const yMax = Math.max(...data.map((d: any) => d.value), goal || 0) * 1.1 || 10;
        const xScaleFn = (index: number) => (index / (data.length > 1 ? data.length - 1 : 1)) * width;
        const yScaleFn = (value: number) => height - (value / yMax) * height;
        const pts = data.map((d: any, i: number) => ({
            x: xScaleFn(i), y: yScaleFn(d.value), value: d.value, label: labels[i], shipments: d.shipments
        }));
        const line = pts.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');
        const area = `${line} V ${height} H ${pts[0].x} Z`;
        return { linePath: line, areaPath: area, points: pts };
    }, [data, labels, width, height, goal]);

    return (
        <div className={`chart-wrapper-full line-chart-card ${onMaximize ? 'clickable' : ''}`} onClick={() => onMaximize && onMaximize()}>
            <div className="line-chart-header">
                <div><h4>{title}</h4><p>{subtitle}</p></div>
            </div>
            <div className="line-chart-container" ref={containerRef}>
                <svg className="line-chart-svg" viewBox={`0 0 ${width + margin.left + margin.right} ${height + margin.top + margin.bottom}`}>
                    <g transform={`translate(${margin.left},${margin.top})`}>
                        {Array.from({ length: 5 }).map((_, i) => <line key={i} x1="0" x2={width} y1={i * height / 4} y2={i * height / 4} className="line-chart-grid" stroke="#334155" strokeWidth="1" />)}
                        {goal && <line className="line-chart-goal" x1="0" x2={width} y1={height - (goal / (Math.max(...data.map((d:any) => d.value), goal) * 1.1 || 10)) * height} y2={height - (goal / (Math.max(...data.map((d:any) => d.value), goal) * 1.1 || 10)) * height} />}
                        <path className="line-chart-area" d={areaPath} style={{ fill: color, opacity: 0.1 }} />
                        <path className="line-chart-line" d={linePath} style={{ stroke: color }} />
                        {points.map((p, i) => (
                            <g key={i} className="line-chart-point-group" onClick={(e) => { e.stopPropagation(); onPointClick && onPointClick(`${title} in ${p.label}`, p.shipments); }}>
                                <circle className="line-chart-point" cx={p.x} cy={p.y} style={{ stroke: color }} />
                                <text className="line-chart-data-label" x={p.x} y={p.y - 10} textAnchor="middle">{p.value}</text>
                            </g>
                        ))}
                    </g>
                </svg>
            </div>
        </div>
    );
};

