                importer: r['Importer'] || r['Cliente'],
                taxes: r['Taxes'] || r['Impostos'],
                status: r['Status'] || 'ORDER PLACED',
                // ... map other fields
            }));
            onUpload(mapped);
        };
        reader.readAsBinaryString(file);
    };

