const CustomsBrokeragePage = ({ shipments }: { shipments: Shipment[] }) => {
    const [selectedShipments, setSelectedShipments] = useState<{title: string, data: Shipment[]} | null>(null);

    const stats = useMemo(() => {
        const totalProcesses = shipments.length;
        const totalCIF = shipments.reduce((acc, p) => acc + (p.invoiceValue || 0), 0);
        const totalTaxes = shipments.reduce((acc, p) => acc + (p.taxes || 0), 0);

        const greenCount = shipments.filter(p => p.parametrization && p.parametrization.toLowerCase().includes('green')).length;
        const greenChannelPercentage = totalProcesses ? ((greenCount / totalProcesses) * 100).toFixed(1) : '0.0';

        const clearedShipments = shipments.filter(s => s.diRegistrationDate && s.greenChannelOrDeliveryAuthorizedDate);
        const totalCustomsDays = clearedShipments.reduce((acc, s) => {
             const days = calculateDaysBetween(s.diRegistrationDate, s.greenChannelOrDeliveryAuthorizedDate);
             return acc + (days || 0);
        }, 0);
        const avgLeadTimeCustoms = clearedShipments.length ? (totalCustomsDays / clearedShipments.length).toFixed(1) : '0.0';

        // 1. Channel Distribution
        const channelCounts: Record<string, number> = {};
        shipments.forEach(s => {
            let channel = 'A AGUARDAR';
            if (s.parametrization) {
                const p = s.parametrization.toUpperCase();
                if (p.includes('VERDE') || p.includes('GREEN')) channel = 'VERDE';
                else if (p.includes('AMARELO') || p.includes('YELLOW')) channel = 'AMARELO';
                else if (p.includes('VERMELHO') || p.includes('RED')) channel = 'VERMELHO';
                else if (p.includes('CINZA') || p.includes('GRAY')) channel = 'CINZA';
            }
            channelCounts[channel] = (channelCounts[channel] || 0) + 1;
        });

        const channelMapColor: Record<string, string> = { 'VERDE': '#22c55e', 'AMARELO': '#facc15', 'VERMELHO': '#ef4444', 'CINZA': '#6b7280', 'A AGUARDAR': '#94a3b8' };
        const channelDistribution = Object.entries(channelCounts).map(([label, value]) => ({
            label, value, shipments: [], color: channelMapColor[label] || '#000'
        }));

        // 2. Top Importers
        const importerVol: Record<string, number> = {};
        shipments.forEach(s => {
            const imp = s.importer || 'Unknown';
            importerVol[imp] = (importerVol[imp] || 0) + (s.invoiceValue || 0);
        });
        const importerRanking = Object.entries(importerVol)
            .map(([label, value]) => ({ label, value, shipments: [] }))
            .sort((a, b) => b.value - a.value)
            .slice(0, 10);

        // 3. Daily Volume
        const dailyVol: Record<string, number> = {};
        shipments.forEach(s => {
            if(s.diRegistrationDate) {
                 const dateKey = formatDate(s.diRegistrationDate); 
                 dailyVol[dateKey] = (dailyVol[dateKey] || 0) + 1;
            }
        });
        const dailyVolume = Object.entries(dailyVol).map(([label, value]) => ({ label, value, shipments: [] }));

        return {
            kpis: { totalProcesses, totalCIF, totalTaxes, greenChannelPercentage, avgLeadTimeCustoms },
            charts: { channelDistribution, importerRanking, dailyVolume }
        };
    }, [shipments]);

    const handleChartClick = (title: string, data: Shipment[]) => {
        setSelectedShipments({ title: `Drilldown: ${title}`, data: [] }); // Placeholder drilldown
    };

    return (
        <div className="brokerage-kpi-page">
             <header className="kpi-page-header">
                <h1>Brokerage & Customs Dashboard</h1>
                <h2>Monitor DIs, Channel Efficiency and Clearance Times</h2>
            </header>

            <div className="kpi-grid">
                <KPIMetricCard icon={<span className="material-symbols-outlined">description</span>} title="Total DIs Registered" value={stats.kpis.totalProcesses} />
                <KPIMetricCard icon={<span className="material-symbols-outlined">payments</span>} title="Total CIF Value" value={stats.kpis.totalCIF.toLocaleString('en-US', {style:'currency', currency: 'USD', maximumFractionDigits:0})} />
                <KPIMetricCard icon={<span className="material-symbols-outlined">verified</span>} title="Green Channel %" value={`${stats.kpis.greenChannelPercentage}%`} />
                <KPIMetricCard icon={<span className="material-symbols-outlined">timer</span>} title="Avg Customs Time" value={`${stats.kpis.avgLeadTimeCustoms} days`} />
            </div>

            <div className="dashboard-grid" style={{marginTop: '1.5rem'}}>
                 <div className="chart-wrapper-full">
                    <DoughnutChart title="Channel Distribution" data={stats.charts.channelDistribution} size={200} />
                 </div>
                 <div className="chart-wrapper-full">
                    <HorizontalBarChart title="Top Importers (CIF)" data={stats.charts.importerRanking} colorMap={{}} />
                 </div>
            </div>
             <div className="chart-wrapper-full" style={{marginTop: '1.5rem'}}>
                <h4 className="v-bar-chart-title">Daily Registration Volume</h4>
                <HorizontalBarChart title="" data={stats.charts.dailyVolume} colorMap={{}} />
            </div>
        </div>
    );
};

const UploadModal: React.FC<UploadModalProps> = ({ isOpen, onClose, onUpload }) => {
  const [file, setFile] = useState<File | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const f = e.target.files?.[0];
    if (f) {
        setFile(f);
        setError('');
        setSuccess('');
    }
  };

  const handleUpload = () => {
    if (!file) {
      setError('Please select a file first.');
      return;
    }
    setIsUploading(true);
    setError('');
    setSuccess('');

    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];
        const json = XLSX.utils.sheet_to_json(worksheet, { header: 1 });

        const headers = json[0] as string[];
        const rows = json.slice(1);

        const shipmentsToUpload = rows.map((rowArray: any[], index: number) => {
            let shipment: Partial<Shipment> = { id: `row-${index}` };
            headers.forEach((header, i) => {
                const key = header.toLowerCase().replace(/\s+/g, '');
                const value = rowArray[i];
                if (key.includes('bl')) shipment.blAwb = value;
                if (key.includes('description') || key.includes('cargo')) shipment.typeOfCargo = value;
                if (key.includes('costcenter')) shipment.costCenter = value;
                if (key.includes('status')) shipment.status = value;
                if (key.includes('eta')) shipment.actualEta = parseDateFromExcel(value);
                if (key.includes('etd')) shipment.actualEtd = parseDateFromExcel(value);
                if (key.includes('incoterm')) shipment.incoterm = value;
                if (key.includes('posap')) shipment.poSap = value;
                if (key.includes('approveddraftdi')) shipment.approvedDraftDi = value;
                if (key.includes('bondedwarehouse')) shipment.bondedWarehouse = value;
                if (key.includes('fcl')) shipment.fcl = typeof value === 'number' ? value : 0;
                if (key.includes('invoicevalue')) shipment.invoiceValue = typeof value === 'number' ? value : 0;
                if (key.includes('parametrization')) shipment.parametrization = value;
                if (key.includes('cargopresence')) shipment.cargoPresenceDate = parseDateFromExcel(value);
                if (key.includes('diregistration')) shipment.diRegistrationDate = parseDateFromExcel(value);
                if (key.includes('greenchannel') || key.includes('deliveryauthorized')) shipment.greenChannelOrDeliveryAuthorizedDate = parseDateFromExcel(value);
                if (key.includes('firsttruck')) shipment.firstTruckDelivery = parseDateFromExcel(value);
                if (key.includes('lasttruck')) shipment.lastTruckDelivery = parseDateFromExcel(value);
                if (key.includes('nfissue')) shipment.nfIssueDate = parseDateFromExcel(value);
                if (key.includes('di') && !key.includes('registration') && !key.includes('draft') && !key.includes('cif')) shipment.di = value;
                if (key.includes('uniquedi')) shipment.uniqueDi = value;
                if (key.includes('importer') || key.includes('cliente')) shipment.importer = value;
                if (key.includes('taxes') || key.includes('impostos')) shipment.taxes = typeof value === 'number' ? value : 0;
            });
            return shipment as Shipment;
        }).filter((s: Partial<Shipment>) => s.blAwb);

        await onUpload(shipmentsToUpload as Shipment[]);

        setSuccess(`${shipmentsToUpload.length} shipments processed successfully!`);
        setFile(null);

      } catch (err) {
        console.error(err);
        setError('Failed to process the Excel file. Please check the format.');
      } finally {
        setIsUploading(false);
      }
    };
    reader.readAsArrayBuffer(file);
  };

   const resetState = () => {
        setFile(null);
        setIsUploading(false);
        setError('');
        setSuccess('');
    };

    const handleClose = () => {
        resetState();
        onClose();
    };


  return (
    <Modal isOpen={isOpen} onClose={handleClose}>
        <div className="modal-header">
            <h3>Upload Shipments</h3>
            <button onClick={handleClose}><span className="material-symbols-outlined">close</span></button>
        </div>
        <div className="modal-body">
            {error && <div className="error-banner">{error}</div>}
            {success && <div className="success-banner">{success}</div>}

            <div className="file-drop-area"
                onClick={() => fileInputRef.current?.click()}
                onDragOver={(e) => e.preventDefault()}
                onDrop={(e) => { 
                    e.preventDefault(); 
                    if(e.dataTransfer.files && e.dataTransfer.files.length > 0) {
                        setFile(e.dataTransfer.files[0]); 
                    }
                }}
            >
                <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".xlsx, .xls" style={{ display: 'none' }} />
                {file ? (
                    <p>Selected file: {file.name}</p>
                ) : (
                    <>
                        <span className="material-symbols-outlined">cloud_upload</span>
                        <p>Drag & drop your Excel file here, or click to select.</p>
                    </>
                )}
            </div>
        </div>
        <div className="modal-actions-footer">
            <button className="btn-secondary" onClick={handleClose}>Cancel</button>
            <button className="btn-primary" onClick={handleUpload} disabled={!file || isUploading}>
                {isUploading ? <LoadingSpinner/> : 'Upload'}
            </button>
        </div>
    </Modal>
  );
};

