// ---------------------------
// Brokerage KPIs PAGE
// ---------------------------

const BrokerageKPIsPage: React.FC<{ shipments: Shipment[] }> = ({
  shipments,
}) => {
  const [filters, setFilters] = useState<BrokerageFilters>({
    importer: 'All',
    channel: 'All',
    startDate: '',
    endDate: '',
  });

  const [selectedShipments, setSelectedShipments] = useState<{
    title: string;
    data: Shipment[];
  } | null>(null);

  const handleChartClick = (title: string, data: Shipment[]) => {
    setSelectedShipments({ title: `Shipments – ${title}`, data });
  };

  const handleFilterChange = (filterName: keyof BrokerageFilters, value: any) => {
    setFilters((prev) => ({ ...prev, [filterName]: value }));
  };

  const diffDays = (start?: string, end?: string): number | null => {
    if (!start || !end) return null;
    const d1 = new Date(start);
    const d2 = new Date(end);
    if (isNaN(d1.getTime()) || isNaN(d2.getTime())) return null;
    return Math.floor(
      (d2.getTime() - d1.getTime()) / (1000 * 60 * 60 * 24),
    );
  };

  type BrokerProcessLite = {
    shipment: Shipment;
    importer: string;
    channel: BrokerChannel;
    cifValue: number;
    taxes: number;
    arrivalDate?: string;
    registrationDate?: string;
    clearanceDate?: string;
    leadArrivalToRegister: number | null;
    leadRegisterToClear: number | null;
    totalLead: number | null;
  };

  const allBrokerProcesses = useMemo<BrokerProcessLite[]>(() => {
    return shipments
      .filter((s) => s.di) // só quem tem DI
      .map((s) => {
        const importerName = s.importer || 'BYD';
        const channel = mapParametrizationToChannel(s.parametrization);

        let cifValue = 0;
        if (s.cifDi) {
          const parsed = parseFloat(
            s.cifDi
              .replace(/[^\d,.-]/g, '')
              .replace(',', '.'),
          );
          cifValue = isNaN(parsed) ? 0 : parsed;
        } else if (typeof s.invoiceValue === 'number') {
          cifValue = s.invoiceValue;
        }

        const taxes = typeof s.taxes === 'number' ? s.taxes : 0;

        const arrivalDate = s.actualEta;
        const registrationDate = s.diRegistrationDate;
        const clearanceDate =
          s.greenChannelOrDeliveryAuthorizedDate;

        const leadArrivalToRegister = diffDays(
          arrivalDate,
          registrationDate,
        );
        const leadRegisterToClear = diffDays(
          registrationDate,
          clearanceDate,
        );
        const totalLead = diffDays(arrivalDate, clearanceDate);

        return {
          shipment: s,
          importer: importerName,
          channel,
          cifValue,
          taxes,
          arrivalDate,
          registrationDate,
          clearanceDate,
          leadArrivalToRegister,
          leadRegisterToClear,
          totalLead,
        };
      });
  }, [shipments]);

  const filteredProcesses = useMemo(() => {
    return allBrokerProcesses.filter((p) => {
      const { importer, channel, registrationDate } = p;
      const { importer: fImp, channel: fCh, startDate, endDate } = filters;

      const importerMatch = fImp === 'All' || importer === fImp;
      const channelMatch = fCh === 'All' || p.channel === fCh;

      let dateMatch = true;
      if (startDate || endDate) {
        if (!registrationDate) return false;
        const reg = registrationDate.split('T')[0];
        if (startDate && reg < startDate) dateMatch = false;
        if (endDate && reg > endDate) dateMatch = false;
      }

      return importerMatch && channelMatch && dateMatch;
    });
  }, [allBrokerProcesses, filters]);

  const kpiMetrics = useMemo(() => {
    const totalProcesses = filteredProcesses.length;
    const totalCIF = filteredProcesses.reduce(
      (sum, p) => sum + p.cifValue,
      0,
    );
    const totalTaxes = filteredProcesses.reduce(
      (sum, p) => sum + p.taxes,
      0,
    );

    const greenCount = filteredProcesses.filter(
      (p) => p.channel === 'VERDE',
    ).length;
    const greenChannelPercentage =
      totalProcesses > 0
        ? ((greenCount / totalProcesses) * 100).toFixed(1)
        : '0.0';

    const cleared = filteredProcesses.filter((p) => p.clearanceDate);

    const avg = (arr: (number | null)[]) => {
      const vals = arr.filter((v): v is number => v !== null);
      if (!vals.length) return 0;
      return vals.reduce((a, b) => a + b, 0) / vals.length;
    };

