const parseCifValue = (cifDi: any, invoiceValue: any): number => {
  // Se vier preenchido no campo cifDi
  if (cifDi !== undefined && cifDi !== null && cifDi !== '') {
    if (typeof cifDi === 'number') {
      return cifDi;
    }
    // Trata string tipo "R$ 1.000,00"
    const parsed = parseFloat(
      String(cifDi)
        .replace(/[^\d.,-]/g, '')
        .replace(',', '.')
    );
    return isNaN(parsed) ? 0 : parsed;
  }

  // Senão, cai pro invoiceValue se for número
  if (typeof invoiceValue === 'number') {
    return invoiceValue;
  }

  return 0;
};

