const DashboardPage = ({ shipments, onNavigate }) => {
    const kpiData = useMemo(() => {
        const now = new Date();
        const thirtyDaysAgo = new Date(now.getFullYear(), now.getMonth(), now.getDate() - 30);
        const recent = shipments.filter(s => s.actualEta && new Date(s.actualEta) > thirtyDaysAgo);
        return {
            totalValue: recent.reduce((sum: number, s) => sum + (s.invoiceValue || 0), 0),
            inTransit: shipments.filter(s => s.status === 'IN TRANSIT').length,
            totalShipments: shipments.length
        };
    }, [shipments]);

    const statusData = useMemo(() => {
        const counts = { 'Order Placed': 0, 'In Transit': 0, 'At Port': 0, 'Delivered': 0 };
        shipments.forEach(s => {
            if (s.status === 'ORDER PLACED') counts['Order Placed']++;
            else if (s.status === 'IN TRANSIT') counts['In Transit']++;
            else if (s.status === 'AT THE PORT' || s.status === 'CARGO READY') counts['At Port']++;
            else if (s.status === 'CARGO DELIVERED') counts['Delivered']++;
        });
        return Object.entries(counts).map(([k, v]) => ({ label: k, value: v, color: k === 'In Transit' ? '#3b82f6' : k === 'At Port' ? '#ef4444' : k === 'Delivered' ? '#10b981' : '#6c757d', shipments: [] }));
    }, [shipments]);

    return (
        <div className="dashboard-page">
             <div className="dashboard-welcome-section">
                <h1>Welcome back!</h1>
                <div className="quick-actions-grid">
                    <button className="quick-action-card"><span className="material-symbols-outlined">add_box</span>Create Entry</button>
                    <button className="quick-action-card"><span className="material-symbols-outlined">local_shipping</span>Track</button>
                </div>
            </div>
            <div className="kpi-grid">
                 <div className="kpi-card"><div className="kpi-header-row"><span className="kpi-title">In Transit</span></div><div className="kpi-value">{kpiData.inTransit}</div></div>
                 <div className="kpi-card"><div className="kpi-header-row"><span className="kpi-title">Total Value (30d)</span></div><div className="kpi-value">{kpiData.totalValue.toLocaleString('en-US', {style:'currency', currency:'USD', maximumFractionDigits:0})}</div></div>
            </div>
            <div className="dashboard-grid">
                <div className="dashboard-card chart-card">
                     <h3>Shipment Status</h3>
                     <DoughnutChart title="" data={statusData} />
                </div>
            </div>
        </div>
    );
};

