const CustomsBrokeragePage = ({ shipments }: { shipments: Shipment[] }) => {
    const [selectedShipments, setSelectedShipments] = useState<{title: string, data: Shipment[]} | null>(null);

    const stats = useMemo(() => {
        const totalProcesses = shipments.length;
        const totalCIF = shipments.reduce((acc, p) => acc + (p.invoiceValue || 0), 0);
        const totalTaxes = shipments.reduce((acc, p) => acc + (p.taxes || 0), 0);

        const greenCount = shipments.filter(p => p.parametrization && p.parametrization.toLowerCase().includes('green')).length;
        const greenChannelPercentage = totalProcesses ? ((greenCount / totalProcesses) * 100).toFixed(1) : '0.0';

        const cleared = shipments.filter(s => s.greenChannelOrDeliveryAuthorizedDate && s.diRegistrationDate);
        const totalDays = cleared.reduce((acc, s) => acc + (calculateDaysBetween(s.diRegistrationDate, s.greenChannelOrDeliveryAuthorizedDate) || 0), 0);
        const avgCustomsTime = cleared.length ? (totalDays / cleared.length).toFixed(1) : '0.0';

        // Charts
        const channelCounts: Record<string, number> = {};
        shipments.forEach(s => {
            let ch = 'A AGUARDAR';
            if (s.parametrization) {
                const p = s.parametrization.toUpperCase();
                if (p.includes('VERDE') || p.includes('GREEN')) ch = 'VERDE';
                else if (p.includes('AMARELO') || p.includes('YELLOW')) ch = 'AMARELO';
                else if (p.includes('VERMELHO') || p.includes('RED')) ch = 'VERMELHO';
                else if (p.includes('CINZA') || p.includes('GRAY')) ch = 'CINZA';
            }
            channelCounts[ch] = (channelCounts[ch] || 0) + 1;
        });
        const channelDist = Object.entries(channelCounts).map(([k, v]) => ({ 
            label: k, value: v, shipments: [], 
            color: k === 'VERDE' ? '#22c55e' : k === 'AMARELO' ? '#facc15' : k === 'VERMELHO' ? '#ef4444' : '#6b7280' 
        }));

        const importerVol: Record<string, number> = {};
        shipments.forEach(s => {
            const imp = s.importer || 'Unknown';
            importerVol[imp] = (importerVol[imp] || 0) + (s.invoiceValue || 0);
        });
        const importerRanking = Object.entries(importerVol)
            .map(([label, value]) => ({ label, value, shipments: [] }))
            .sort((a, b) => b.value - a.value)
            .slice(0, 10);

        const dailyVol: Record<string, number> = {};
        shipments.forEach(s => {
            if(s.diRegistrationDate) {
                 const dateKey = formatDate(s.diRegistrationDate); 
                 dailyVol[dateKey] = (dailyVol[dateKey] || 0) + 1;
            }
        });
        const dailyVolume = Object.entries(dailyVol).map(([label, value]) => ({ label, value, shipments: [] }));

        return {
            kpis: { totalProcesses, totalCIF, totalTaxes, greenChannelPercentage, avgCustomsTime },
            charts: { channelDist, importerRanking, dailyVolume }
        };
    }, [shipments]);

    const handleChartClick = (title: string, data: Shipment[]) => {
        setSelectedShipments({ title: `Drilldown: ${title}`, data: [] });
    };

    return (
        <div className="brokerage-kpi-page">
            <header className="kpi-page-header">
                <h1>Brokerage & Customs Dashboard</h1>
            </header>
            <div className="kpi-grid">
                <KPIMetricCard icon={<span className="material-symbols-outlined">description</span>} title="Total DIs" value={stats.kpis.totalProcesses} />
                <KPIMetricCard icon={<span className="material-symbols-outlined">payments</span>} title="Total CIF" value={stats.kpis.totalCIF.toLocaleString('en-US', {style: 'currency', currency: 'USD', maximumFractionDigits: 0})} />
                <KPIMetricCard icon={<span className="material-symbols-outlined">verified</span>} title="Green Channel %" value={stats.kpis.greenChannelPercentage + '%'} />
                <KPIMetricCard icon={<span className="material-symbols-outlined">timer</span>} title="Avg Customs Time" value={stats.kpis.avgCustomsTime + ' days'} />
            </div>
            <div className="dashboard-grid" style={{marginTop: '1.5rem'}}>
                <div className="chart-wrapper-full">
                    <DoughnutChart title="Channel Distribution" data={stats.charts.channelDist} size={200} />
                </div>
                 <div className="chart-wrapper-full">
                    <HorizontalBarChart title="Top Importers (CIF)" data={stats.charts.importerRanking} />
                 </div>
            </div>
             <div className="chart-wrapper-full" style={{marginTop: '1.5rem'}}>
                <h4 className="v-bar-chart-title">Daily Registration Volume</h4>
                <HorizontalBarChart title="" data={stats.charts.dailyVolume} />
            </div>
        </div>
    );
};

const ImportsPage = ({ shipments, onUpload }: any) => {
    const fileInputRef = useRef<HTMLInputElement>(null);
    const handleFile = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if(!file) return;
        const reader = new FileReader();
        reader.onload = (evt) => {
            const bstr = evt.target?.result;
            const wb = XLSX.read(bstr, { type: 'binary' });
            const ws = wb.Sheets[wb.SheetNames[0]];
            const data = XLSX.utils.sheet_to_json(ws);
            const mapped = data.map((r: any, i: number) => ({
                id: `row-${i}`,
                blAwb: r['BL'] || r['BL/AWB'],
                importer: r['Importer'] || r['Cliente'] || r['IMPORTADOR'],
                taxes: r['Taxes'] || r['Impostos'] || r['IMPOSTOS'],
                status: r['Status'] || 'ORDER PLACED',
                di: r['DI'] || r['DECLARACAO'],
                invoiceValue: r['CIF'] || r['VALOR ADUANEIRO'],
                parametrization: r['CANAL'] || r['PARAMETRIZACAO'],
                diRegistrationDate: parseDateFromExcel(r['REGISTRO'] || r['DATA DI']),
                greenChannelOrDeliveryAuthorizedDate: parseDateFromExcel(r['DESEMBARACO'] || r['CI'] || r['CLEARANCE'])
            }));
            onUpload(mapped);
        };
        reader.readAsBinaryString(file);
    };

    return (
        <div className="imports-page">
            <div className="page-header"><h1>Imports</h1> <button className="btn-primary" onClick={() => fileInputRef.current?.click()}>Upload</button></div>
            <input type="file" ref={fileInputRef} style={{display: 'none'}} onChange={handleFile} />
            <ShipmentsTable title="All Imports" shipments={shipments} onClose={() => {}} />
        </div>
    );
};

const App = () => {
    const [user, setUser] = useState<any>(null);
    const [activePage, setActivePage] = useState('Dashboard');
    const [shipments, setShipments] = useState<Shipment[]>([]);
    const [isSidebarCollapsed, setSidebarCollapsed] = useState(false);

    useEffect(() => {
        const unsub = auth.onAuthStateChanged(u => setUser(u));
        return () => unsub();
    }, []);

    const handleUpload = (data: Shipment[]) => {
        setShipments(data);
    };

    if (!user) return <LoginPage onLoginSuccess={() => {}} />;

    const renderPage = () => {
        switch (activePage) {
            case 'Dashboard': return <DashboardPage shipments={shipments} onNavigate={setActivePage} />;
            case 'Imports': return <ImportsPage shipments={shipments} onUpload={handleUpload} />;
            case 'KPIs': return <KPIsPage shipments={shipments} />;
            case 'Brokerage KPIs': return <BrokerageKPIsPage shipments={shipments} />;
            case 'Customs Brokerage': return <CustomsBrokeragePage shipments={shipments} />;
            default: return <div>Page not found</div>;
        }
    };

    const navItems = [
        { name: 'Dashboard', icon: 'dashboard' },
        { name: 'Imports', icon: 'directions_boat' },
        { name: 'KPIs', icon: 'bar_chart' },
        { name: 'Brokerage KPIs', icon: 'pie_chart' },
        { name: 'Customs Brokerage', icon: 'local_shipping' },
    ];

    return (
        <div className={`app-container ${isSidebarCollapsed ? 'sidebar-collapsed' : ''}`}>
             <aside className={`sidebar ${isSidebarCollapsed ? 'collapsed' : ''}`}>
                <header className="sidebar-header">
                    <span>Navigator</span>
                     <button className="sidebar-toggle" onClick={() => setSidebarCollapsed(!isSidebarCollapsed)}>
                        <span className="material-symbols-outlined">menu_open</span>
                    </button>
                </header>
                <nav>
                    <ul className="nav-links">
                        {navItems.map(item => (
                            <li key={item.name}>
                                <a href="#" className={`nav-link ${activePage === item.name ? 'active' : ''}`} onClick={() => setActivePage(item.name)}>
                                    <span className="material-symbols-outlined nav-icon">{item.icon}</span>
                                    <span className="nav-label">{item.name}</span>
                                </a>
                            </li>
                        ))}
                    </ul>
                </nav>
                <footer className="sidebar-footer">
                    <button className="nav-link" onClick={() => auth.signOut()}>
                        <span className="material-symbols-outlined nav-icon">logout</span>
                        <span className="nav-label">Logout</span>
                    </button>
                </footer>
            </aside>
            <main className="main-content">
                {renderPage()}
            </main>
        </div>
    );
};

const root = createRoot(document.getElementById('root')!);
root.render(<App />);
